// Valida x-hub-signature-256 contra WHATSAPP_APP_SECRET
// Devuelve { error, error_type } en vez de throw — el logging a LangFuse ocurre en el nodo siguiente.
const crypto = require('crypto');
const signature = $input.first().json.headers?.['x-hub-signature-256'];
const appSecret = $env.WHATSAPP_APP_SECRET;
const body = JSON.stringify($input.first().json.body);
const expectedSignature = 'sha256=' + crypto.createHmac('sha256', appSecret).update(body).digest('hex');

if (signature !== expectedSignature) {
  return [{ json: { error: true, error_type: 'INVALID_SIGNATURE', ts: new Date().toISOString() } }];
}

const entry = $input.first().json.body.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];
const contact = change?.value?.contacts?.[0];
const metadata = change?.value?.metadata;

if (!message) {
  return [{ json: { error: true, error_type: 'NO_MESSAGE', ts: new Date().toISOString() } }];
}

return [{
  json: {
    error: false,
    wa_message_id: message.id,
    phone: message.from,
    timestamp: message.timestamp,
    type: message.type,
    content: {
      body: message.text?.body ?? null,
      media_id: message.audio?.id ?? message.image?.id ?? null,
      mime_type: message.audio?.mime_type ?? message.image?.mime_type ?? null,
      caption: message.image?.caption ?? null
    },
    contact_name: contact?.profile?.name ?? null,
    phone_number_id: metadata?.phone_number_id
  }
}];
